SELECT s.isin, s.mnemonic, s.security_desc, n.title, n.content, n.published_at
FROM securities s
JOIN news n ON s.security_id = n.security_id;

SELECT COUNT(*) AS number_of_trading_activities
FROM trading_activities
WHERE security_id = 10;

SELECT security_id, AVG(average_trade_size) AS average_trade_size
FROM trading_activities
GROUP BY security_id;

SELECT * 
FROM trading_activities 
WHERE security_id = 1;
